INSERT INTO terms (id, category_id, title, content, created_at, updated_at) VALUES (1, 11, 'Regulamin ogolny wypozyczania narzedzi', 'REGULAMIN WYPOZYCZANIA NARZEDZI. 1. Aplikacja sluzy do laczenia czlonkow lokalnej spolecznosci. 2. Wszystkie transakcje odbywaja sie poza aplikacja. 3. Najemca odpowiada za narzedzie od odbioru do zwrotu. 4. Narzedzie nalezy zwrocic w terminie i w stanie niepogorszonym.', '2025-01-01 10:00:00', '2025-01-01 10:00:00');
INSERT INTO terms (id, category_id, title, content, created_at, updated_at) VALUES (2, 1, 'Regulamin wypozyczania narzedzi ogrodniczych', 'REGULAMIN NARZEDZI OGRODNICZYCH. 1. Dotyczy kosiarek, sekatorow, szpadli. 2. Transakcje poza aplikacja. 3. Narzedzia zwrocic czyste i suche. 4. Najemca odpowiada za szkody.', '2025-01-01 10:00:00', '2025-01-01 10:00:00');
INSERT INTO terms (id, category_id, title, content, created_at, updated_at) VALUES (3, 2, 'Regulamin wypozyczania narzedzi budowlanych', 'REGULAMIN NARZEDZI BUDOWLANYCH. 1. Dotyczy wiertelek, mlotow, szlifierek. 2. Transakcje poza aplikacja. 3. Przestrzegac zasad BHP. 4. Narzedzia zwrocic czyste z kompletem akcesorii.', '2025-01-01 10:00:00', '2025-01-01 10:00:00');
INSERT INTO terms (id, category_id, title, content, created_at, updated_at) VALUES (4, 3, 'Regulamin wypozyczania narzedzi elektrycznych', 'REGULAMIN NARZEDZI ELEKTRYCZNYCH. 1. Dotyczy wkretarek, szlifierek, pil elektrycznych. 2. Transakcje poza aplikacja. 3. Uzywac zgodnie z instrukcja producenta. 4. Zwrocic z kompletem kabli i akcesoriow.', '2025-01-01 10:00:00', '2025-01-01 10:00:00');
INSERT INTO terms (id, category_id, title, content, created_at, updated_at) VALUES (5, 4, 'Regulamin wypozyczania narzedzi hydraulicznych', 'REGULAMIN NARZEDZI HYDRAULICZNYCH. 1. Dotyczy kluczy, pras, narzedzi do rur. 2. Transakcje poza aplikacja. 3. Narzedzia zwrocic czyste i suche. 4. Najemca odpowiada za szkody.', '2025-01-01 10:00:00', '2025-01-01 10:00:00');
